class Solution:
    def readBinaryWatch(self, turnedOn: int) -> List[str]:
        def bits(x):
            return bin(x).count("1")
        ans = []
        for h in range(12):
            for m in range(60):
                if bits(h) + bits(m) == turnedOn:
                    ans.append(f"{h}:{m:02d}")
        return ans

