class Solution {
public:
    vector<string> readBinaryWatch(int turnedOn) {
        auto bits = [](int x){ return __builtin_popcount(x); };
        vector<string> ans;
        for (int h = 0; h < 12; h++)
            for (int m = 0; m < 60; m++)
                if (bits(h) + bits(m) == turnedOn) {
                    char buf[16];
                    snprintf(buf, sizeof(buf), "%d:%02d", h, m);
                    ans.push_back(buf);
                }
        return ans;
    }
};

