static int popc(int x){ int c=0; while(x){ c+=x&1; x>>=1; } return c; }
char** readBinaryWatch(int turnedOn, int* retSize) {
    char** ans = malloc(720 * sizeof(char*)); *retSize = 0;
    for (int h=0; h<12; h++) for (int m=0; m<60; m++)
        if (popc(h)+popc(m)==turnedOn) {
            ans[*retSize] = malloc(8);
            snprintf(ans[(*retSize)++], 8, "%d:%02d", h, m);
        }
    return ans;
}
